    "description": "```cpp\n#include <algorithm>\n#include <cstdio>\n#include <cstring>\n#define ll long long\nint cnt_broken = 0;\nint cnt_check = 0;\nint n, k;\ninline bool check(int h) {\n    printf(\"now check:%d\\n\", h);\n    ++cnt_check;\n    if (cnt_broken == 2) {\n        printf(\"You have no egg!\\n\");\n        return false;\n    }\n    if (h >= k) {\n        ++cnt_broken;\n        return true;\n    } else {\n        return false;\n    }\n}\ninline bool assert_ans(int h) {\n    if (h == k) {\n        printf(\"You are Right using %d checks\\n\", cnt_check);\n        return true;\n    } else {\n        printf(\"Wrong answer!\\n\");\n        return false;\n    }\n}\ninline void guess1(int n) {\n    for (int i = 1; i <= n; ++i) {\n        if (check(i)) {\n            assert_ans(i);\n            return;\n        }\n    }\n}\ninline void guess2(int n) {\n    int w = 0;\n    for (w = 1; w * (w + 1) / 2 < n; ++w)\n        ;\n    for (int ti = w, nh = w; --ti, nh += ti, nh = std::min(nh, n)) {\n        if (check(nh)) {\n            for (int j = nh - ti + 1; j < nh; ++j) {\n                if (check(j)) {\n                    assert_ans(j);\n                    return;\n                }\n            }\n            assert_ans(nh);\n            return;\n        }\n    }\n}\nint main() {\n    scanf(\"%d\", &n, &k);\n    int t;\n    scanf(\"%d\", &t);\n    if (t == 1) {\n        guess1(n);\n    } else {\n        guess2(n);\n    }\n    return 0;\n}\n```\n\n> (注意：下述的\"猜测数\"为调用 check 函数的次数 (即 cnt_check 的值)；\"猜测正确\"的含义为 assert_ans 函数 return true (执行第 25 行所在分支)的情况；所有输入保证 1 ≤ k ≤ n。)",
