    "title": "阅读程序第 1 题",
    "description": "```cpp\n#include <iostream>\nusing namespace std;\n\nconst int N = 1000;\nint c[N];\n\nint logic(int x, int y) {\n    return (x & y) ^ ((x ^ y) | (~x & y));\n}\n\nvoid generate(int a, int b, int *c) {\n    for (int i = 0; i < b; i++)\n        c[i] = logic(a, i) % (b + 1);\n}\n\nvoid recursion(int depth, int *arr, int size) {\n    if (depth <= 0 || size <= 1) return;\n    int pivot = arr[0];\n    int i = 0, j = size - 1;\n    while (i <= j) {\n        while (arr[i] < pivot) i++;\n        while (arr[j] > pivot) j--;\n        if (i <= j) {\n            int temp = arr[i];\n            arr[i] = arr[j];\n            arr[j] = temp;\n            i++; j--;\n        }\n    }\n    recursion(depth - 1, arr, j + 1);\n    recursion(depth - 1, arr + i, size - i);\n}\n\nint main() {\n    int a, b, d;\n    cin >> a >> b >> d;\n    generate(a, b, c);\n    recursion(d, c, b);\n    for (int i = 0; i < b; ++i) cout << c[i] << \" \";\n    cout << endl;\n}\n\n```",
    "statement": "```cpp\n#include <iostream>\nusing namespace std;\n\nconst int N = 1000;\nint c[N];\n\nint logic(int x, int y) {\n    return (x & y) ^ ((x ^ y) | (~x & y));\n}\n\nvoid generate(int a, int b, int *c) {\n    for (int i = 0; i < b; i++)\n        c[i] = logic(a, i) % (b + 1);\n}\n\nvoid recursion(int depth, int *arr, int size) {\n    if (depth <= 0 || size <= 1) return;\n    int pivot = arr[0];\n    int i = 0, j = size - 1;\n    while (i <= j) {\n        while (arr[i] < pivot) i++;\n        while (arr[j] > pivot) j--;\n        if (i <= j) {\n            int temp = arr[i];\n            arr[i] = arr[j];\n            arr[j] = temp;\n            i++; j--;\n        }\n    }\n    recursion(depth - 1, arr, j + 1);\n    recursion(depth - 1, arr + i, size - i);\n}\n\nint main() {\n    int a, b, d;\n    cin >> a >> b >> d;\n    generate(a, b, c);\n    recursion(d, c, b);\n    for (int i = 0; i < b; ++i) cout << c[i] << \" \";\n    cout << endl;\n}\n\n```",
