    "title": "阅读程序第 3 题",
    "description": "```cpp\n#include <iostream>\n#include <cstring>\n#include <algorithm>\nusing namespace std;\n\nconst int maxn = 1000000 + 5;\nconst int P1 = 998244353, P2 = 1000000007;\nconst int B1 = 2, B2 = 31;\nconst int K1 = 0, K2 = 13;\n\ntypedef long long ll;\n\nint n;\nbool p[maxn];\nint p1[maxn], p2[maxn];\n\nstruct H {\n    int h1, h2, l;\n    H(bool b = false) {\n        h1 = b + K1;\n        h2 = b + K2;\n        l = 1;\n    }\n\n    H operator + (const H & h) const {\n        H hh;\n        hh.l = l + h.l;\n        hh.h1 = (1ll * h1 * p1[h.l] + h.h1) % P1;\n        hh.h2 = (1ll * h2 * p2[h.l] + h.h2) % P2;\n        return hh;\n    }\n\n    bool operator == (const H & h) const {\n        return l == h.l && h1 == h.h1 && h2 == h.h2;\n    }\n\n    bool operator < (const H & h) const {\n        if (l != h.l) return l < h.l;\n        else if (h1 != h.h1) return h1 < h.h1;\n        else return h2 < h.h2;\n    }\n} h[maxn];\n\nvoid init() {\n    memset(p, 1, sizeof(p));\n    p[0] = p[1] = false;\n    p1[0] = p2[0] = 1;\n    for (int i = 1; i <= n; ++i) {\n        p1[i] = (1ll * B1 * p1[i-1]) % P1;\n        p2[i] = (1ll * B2 * p2[i-1]) % P2;\n        if (!p[i]) continue;\n        for (int j = 2 * i; j <= n; j += i) {\n            p[j] = false;\n        }\n    }\n}\n\nint solve() {\n    for (int i = n; i; --i) {\n        h[i] = H(p[i]);\n        if (2 * i + 1 <= n) {\n            h[i] = h[2 * i] + h[i] + h[2 * i + 1];\n        } else if (2 * i <= n) {\n            h[i] = h[2 * i] + h[i];\n        }\n    }\n\n    cout << h[1].h1 << endl;\n    sort(h + 1, h + n + 1);\n    int m = unique(h + 1, h + n + 1) - (h + 1);\n    return m;\n}\n\nint main() {\n    cin >> n;\n    init();\n    cout << solve() << endl;\n}\n\n```",
    "statement": "```cpp\n#include <iostream>\n#include <cstring>\n#include <algorithm>\nusing namespace std;\n\nconst int maxn = 1000000 + 5;\nconst int P1 = 998244353, P2 = 1000000007;\nconst int B1 = 2, B2 = 31;\nconst int K1 = 0, K2 = 13;\n\ntypedef long long ll;\n\nint n;\nbool p[maxn];\nint p1[maxn], p2[maxn];\n\nstruct H {\n    int h1, h2, l;\n    H(bool b = false) {\n        h1 = b + K1;\n        h2 = b + K2;\n        l = 1;\n    }\n\n    H operator + (const H & h) const {\n        H hh;\n        hh.l = l + h.l;\n        hh.h1 = (1ll * h1 * p1[h.l] + h.h1) % P1;\n        hh.h2 = (1ll * h2 * p2[h.l] + h.h2) % P2;\n        return hh;\n    }\n\n    bool operator == (const H & h) const {\n        return l == h.l && h1 == h.h1 && h2 == h.h2;\n    }\n\n    bool operator < (const H & h) const {\n        if (l != h.l) return l < h.l;\n        else if (h1 != h.h1) return h1 < h.h1;\n        else return h2 < h.h2;\n    }\n} h[maxn];\n\nvoid init() {\n    memset(p, 1, sizeof(p));\n    p[0] = p[1] = false;\n    p1[0] = p2[0] = 1;\n    for (int i = 1; i <= n; ++i) {\n        p1[i] = (1ll * B1 * p1[i-1]) % P1;\n        p2[i] = (1ll * B2 * p2[i-1]) % P2;\n        if (!p[i]) continue;\n        for (int j = 2 * i; j <= n; j += i) {\n            p[j] = false;\n        }\n    }\n}\n\nint solve() {\n    for (int i = n; i; --i) {\n        h[i] = H(p[i]);\n        if (2 * i + 1 <= n) {\n            h[i] = h[2 * i] + h[i] + h[2 * i + 1];\n        } else if (2 * i <= n) {\n            h[i] = h[2 * i] + h[i];\n        }\n    }\n\n    cout << h[1].h1 << endl;\n    sort(h + 1, h + n + 1);\n    int m = unique(h + 1, h + n + 1) - (h + 1);\n    return m;\n}\n\nint main() {\n    cin >> n;\n    init();\n    cout << solve() << endl;\n}\n\n```",
