    "description": "（2）（次短路）已知一个有 n 个点 m 条边的有向图 G，并且给定图中的两个点 s 和 t，求次短路（长度严格大于最短路的最短路径）。如果不存在，输出一行 \"-1\"。如果存在，输出两行，第一行表示次短路的长度，第二行表示次短路的一个方案。\n\n```cpp\n#include <cstdio>\n#include <queue>\n#include <utility>\n#include <cstring>\nusing namespace std;\n\nconst int maxn = 2e5+10, maxm = 1e6+10, inf = 522133279;\n\nint n, m, s, t;\nint head[maxn], nxt[maxm], to[maxm], w[maxm], tot = 1;\nint dis[maxn<<1], *dis2;\nint pre[maxn<<1], *pre2;\nbool vis[maxn<<1];\n\nvoid add(int a, int b, int c) {\n    ++tot;\n    nxt[tot] = head[a];\n    to[tot] = b;\n    w[tot] = c;\n    head[a] = tot;\n}\n\nbool upd(int a, int b, int d, priority_queue<pair<int, int>> &q) {\n    if (d >= dis[b]) return false;\n    if (b < n) ___①___;\n    q.push(___②___);\n    dis[b] = d;\n    pre[b] = a;\n    return true;\n}\n\nvoid solve() {\n    priority_queue<pair<int, int>> q;\n    q.push(make_pair(0, s));\n    memset(dis, ___③___, sizeof(dis));\n    memset(pre, -1, sizeof(pre));\n    dis2 = dis+n;\n    pre2 = pre+n;\n    dis[s] = 0;\n    while (!q.empty()) {\n        int aa = q.top().second; q.pop();\n        if (vis[aa]) continue;\n        vis[aa] = true;\n        int a = aa % n;\n        for (int e = head[a]; e; e = nxt[e]) {\n            int b = to[e], c = w[e];\n            if (aa < n) {\n                if (!upd(a, b, dis[a]+c, q))\n                    ___④__;\n            } else {\n                upd(n+a, n+b, dis2[a]+c, q);\n        }\n    }\n}\n\nvoid out(int a) {\n    if (a != s) {\n        if (a < n) out(pre[a]);\n        else out(___⑤___);\n    }\n    printf(\"%d%c\", a%n+1, \" \\n\"[a == n+t]);\n}\n\nint main() {\n    scanf(\"%d%d%d%d\", &n, &m, &s, &t);\n    s--, t--;\n    for (int i = 0; i < m; ++i) {\n        int a, b, c;\n        scanf(\"%d%d%d\", &a, &b, &c);\n        add(a-1, b-1, c);\n    }\n    solve();\n    if (dis2[t] == inf) puts(\"-1\");\n    else {\n        printf(\"%d\\n\", dis2[t]);\n        out(n+t);\n    }\n}\n\n```",
